int cmp(const void* a, const void* b) {
    int x = *(int*)a;
    int y = *(int*)b;
    return x - y;
}

int maxContentChildren(int* g, int n, int* s, int m) {
    qsort(g, n, sizeof(int), cmp);
    qsort(s, m, sizeof(int), cmp);

    int i = 0, j = 0;
    while (i < n && j < m) {
        if (s[j] >= g[i]) {
            i++; 
        }
        j++; 
    }
    return i; 
}

