code.JavaScript:
function maxContentChildren(g, s) {
    // Sort greed factors and cookie sizes in ascending order
    g.sort((a, b) => a - b);
    s.sort((a, b) => a - b);

    let childPtr = 0;
    let cookiePtr = 0;

    // Iterate through both arrays
    while (childPtr < g.length && cookiePtr < s.length) {
        // If the current cookie is large enough for the current child
        if (s[cookiePtr] >= g[childPtr]) {
            childPtr++; // The child is content, move to the next child
        }
        // Always move to the next cookie (whether it was used or too small)
        cookiePtr++; 
    }

    // The child pointer represents the number of successfully fed children
    return childPtr;
}
